import json
import pandas as pd
import re

# Load businesses
businesses_path = locals()['var_functions.query_db:28']

if isinstance(businesses_path, str) and businesses_path.endswith('.json'):
    with open(businesses_path, 'r') as f:
        all_businesses = json.load(f)
else:
    all_businesses = locals()['var_functions.query_db:28']

# Extract WiFi businesses with states
wifi_with_states = []

for biz in all_businesses:
    attrs = biz.get('attributes')
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        # Check if WiFi exists and is not "no" or "False"  
        if wifi_val is not None and wifi_val != "u'no'" and wifi_val != 'False':
            # Extract state from description
            desc = biz.get('description', '')
            # Look for pattern: "City, ST" or "in ST,"
            state_match = re.search(r',\s*([A-Z]{2})\b', desc)
            if state_match:
                state = state_match.group(1)
                wifi_with_states.append({
                    'business_id': biz['business_id'],
                    'name': biz['name'],
                    'state': state,
                    'wifi': wifi_val
                })

# Count by state
from collections import Counter
state_counts = Counter([biz['state'] for biz in wifi_with_states])

# Load ratings from user database
reviews = locals()['var_functions.query_db:14']

# Map business_id to state and collect ratings
biz_ratings = {}
for biz in wifi_with_states:
    business_id_num = biz['business_id'].replace('businessid_', '')
    business_ref = f'businessref_{business_id_num}'
    biz_ratings[business_ref] = {
        'state': biz['state'],
        'ratings': []
    }

# Collect ratings for WiFi businesses
for review in reviews:
    business_ref = review['business_ref']
    if business_ref in biz_ratings:
        try:
            rating = int(review['rating'])
            biz_ratings[business_ref]['ratings'].append(rating)
        except:
            pass

# Calculate average rating per business and per state
state_ratings = {}
for biz_ref, data in biz_ratings.items():
    state = data['state']
    if data['ratings']:
        avg_rating = sum(data['ratings']) / len(data['ratings'])
        if state not in state_ratings:
            state_ratings[state] = []
        state_ratings[state].append(avg_rating)

# Calculate overall average per state
state_avg_ratings = {}
for state, ratings in state_ratings.items():
    state_avg_ratings[state] = sum(ratings) / len(ratings)

# Find state with highest number of WiFi businesses
if state_counts:
    top_state = state_counts.most_common(1)[0]
    top_state_name = top_state[0]
    top_state_count = top_state[1]
    top_state_avg_rating = state_avg_ratings.get(top_state_name, 'N/A')
else:
    top_state_name = 'N/A'
    top_state_count = 0
    top_state_avg_rating = 'N/A'

result = {
    'top_state': top_state_name,
    'wifi_business_count': top_state_count,
    'avg_rating': top_state_avg_rating,
    'all_state_counts': dict(state_counts),
    'all_state_avg_ratings': state_avg_ratings
}

print("__RESULT__:")
print(json.dumps(result))

